'use server';

import { updateTag } from 'next/cache';

import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title');
  const body = formData.get('body');

  if (typeof title !== 'string' || !title.trim()) {
    throw new Error('A post title is required.');
  }

  if (typeof body !== 'string' || !body.trim()) {
    throw new Error('Post content is required.');
  }

  addPost(title.trim(), body.trim());

  // updateTag expires the tagged data immediately, so the next render fetches fresh posts.
  updateTag('posts');
}
import 'server-only';

import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: string;
};

const posts: Post[] = [];

export const getPosts = unstable_cache(
  async () => posts.map((post) => ({ ...post })),
  ['posts'],
  { tags: ['posts'] }
);

export function addPost(title: string, body: string): Post {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    body,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);
  return post;
}
import { CreatePostForm } from './create-post-form';
import { getPosts } from '@/lib/posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>
      <CreatePostForm />
      <section aria-label="Posts list">
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          posts.map((post) => (
            <article key={post.id}>
              <h2>{post.title}</h2>
              <p>{post.body}</p>
            </article>
          ))
        )}
      </section>
    </main>
  );
}

